template.content:
{{modelName}}ProfileFormView:
  type: form
  model: {{modelName}}
  description: "Form view for {{modelName}} with profile attachment support"
  subscribes:
    - {{modelName}}Created
    - {{modelName}}Updated
    - ProfileAttachedTo{{modelName}}
    - ProfileDetachedFrom{{modelName}}
    - ProfileUpdatedOn{{modelName}}
  uiComponents:
    - type: FormHeader
      properties:
        name: formHeader
        model: {{modelName}}
        showProgress: true
        showValidation: true

    - type: TabContainer
      properties:
        name: formTabs
        defaultTab: basic
        tabs:
          - name: basic
            label: "Basic Information"
            components:
              - type: FormSection
                properties:
                  title: "{{modelName}} Details"
                  fields:
                    {{#each model.attributes}}
                    {{#unless (eq name "id")}}
                    - name: {{name}}
                      type: {{getInputType type}}
                      label: "{{humanize name}}"
                      required: {{required}}
                      {{#if constraints}}
                      validation: {{constraints}}
                      {{/if}}
                    {{/unless}}
                    {{/each}}

              {{#if relationships.parentRelationships}}
              - type: FormSection
                properties:
                  title: "Relationships"
                  fields:
                    {{#each relationships.parentRelationships}}
                    - name: {{name}}Id
                      type: EntitySelector
                      label: "Select {{targetModel}}"
                      model: {{targetModel}}
                      required: true
                      searchable: true
                      showClearButton: true
                    {{/each}}
              {{/if}}

          {{#each model.profiles}}
          - name: {{name.toLowerCase}}Profile
            label: "{{humanize name}} Profile"
            components:
              - type: ProfileAttachmentPanel
                properties:
                  profileType: {{name}}
                  model: {{../modelName}}
                  allowDetach: true
                  showProfileHistory: true

              - type: FormSection
                properties:
                  title: "{{humanize name}} Details"
                  fields:
                    {{#each attributes}}
                    - name: {{name}}
                      type: {{getInputType type}}
                      label: "{{humanize name}}"
                      required: {{required}}
                      profileField: true
                    {{/each}}
          {{/each}}

    - type: FormControls
      properties:
        name: formControls
        submitLabel: "Save {{modelName}}"
        cancelLabel: Cancel
        showSaveAndContinue: true
        showValidation: true
        validationMode: realtime
